// Import necessary libraries
const { ethers } = require('ethers');
const Web3 = require('web3');

// Set up the provider and signer
const infuraUrl = 'https://mainnet.infura.io/v3/YOUR_PROJECT_ID';
const web3 = new Web3(new Web3.providers.HttpProvider(infuraUrl));
const provider = ethers.getDefaultProvider();
const signer = ethers.Wallet.createRandom();

// Load the contract ABI
const contractAddress = '0xYOUR_CONTRACT_ADDRESS'; // replace with your contract address
const abiFile = require('./path/to/your/contract/abi.json');
const contractABI = abiFile.abi;

// Load the contract instance
const contract = new ethers.Contract(contractAddress, contractABI, provider);

// Function to handle user input and construct transaction
function sendTransaction() {
  const userInput = document.getElementById('userInput').value;
  if (!userInput) return console.error('No input provided');

  // Parse the input data into a buffer
  const inputData = ethers.utils.parseJson(userInput);

  try {
    // Construct the transaction object
    const txCount = await provider.getTransactionCount(signer.address);
    const nonce = new Big(txCount.toString()).toString(16).padStart(64, '0');
    const gasLimit = 100000;
    const gasPrice = 20e9; // adjust to your desired gas price

    const tx = {
      to: contractAddress,
      from: signer.address,
      data: contract.interface.encodeFunctionData('functionName', inputData),
      nonce,
      gasLimit,
      gasPrice,
    };

    // Sign the transaction
    const signedTx = await signer.signTransaction(tx);
    provider.sendSignedTransaction(signedTx.rawTransaction).then((txHash) => {
      console.log(`Transaction sent: ${txHash}`);
    });
  } catch (error) {
    console.error('Error constructing or sending transaction:', error);
  }
}

// Set up event listener
document.getElementById('send').addEventListener('click', sendTransaction);